/** 世界书条目「玩家的游戏历史」内嵌片段标记（脚本自动维护，其余正文可手写） */
export const CHRONICLE_ENTRY_NAME = '玩家的游戏历史';
const MARK_START = '<编年史数据>';
const MARK_END = '</编年史数据>';

const ROUND_RE = /<回合\s+n="(\d+)"\s*>([\s\S]*?)<\/回合\s*>/gi;

function escapeXml(text: string): string {
  return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function sumToXml(sum: string): string {
  if (sum.includes(']]>')) {
    return `<sum>${escapeXml(sum)}</sum>`;
  }
  return `<sum><![CDATA[${sum}]]></sum>`;
}

function parseSumFromRoundInner(inner: string): string {
  const cdata = inner.match(/<sum\s*>\s*<!\[CDATA\[([\s\S]*?)\]\]>\s*<\/sum\s*>/i);
  if (cdata) {
    return cdata[1].trim();
  }
  const plain = inner.match(/<sum\s*>([\s\S]*?)<\/sum\s*>/i);
  return plain?.[1]?.trim() ?? '';
}

export function parseChronicleRounds(fullContent: string): Map<number, string> {
  const map = new Map<number, string>();
  const block = extractChronicleInner(fullContent);
  if (!block.inner.trim()) {
    return map;
  }
  let m: RegExpExecArray | null;
  ROUND_RE.lastIndex = 0;
  while ((m = ROUND_RE.exec(block.inner)) !== null) {
    const n = Number(m[1]);
    if (!Number.isFinite(n)) {
      continue;
    }
    map.set(n, parseSumFromRoundInner(m[2]));
  }
  return map;
}

function extractChronicleInner(fullContent: string): { before: string; inner: string; after: string } {
  const start = fullContent.indexOf(MARK_START);
  const end = fullContent.indexOf(MARK_END);
  if (start === -1 || end === -1 || end < start) {
    return { before: fullContent, inner: '', after: '' };
  }
  return {
    before: fullContent.slice(0, start),
    inner: fullContent.slice(start + MARK_START.length, end),
    after: fullContent.slice(end + MARK_END.length),
  };
}

function serializeChronicleRounds(rounds: Map<number, string>): string {
  const indices = [...rounds.keys()].sort((a, b) => b - a);
  const body = indices
    .map(i => {
      const sum = rounds.get(i) ?? '';
      return `<回合 n="${i}">\n${sumToXml(sum)}\n</回合>`;
    })
    .join('\n\n');
  return body;
}

/** 合并编年史块回完整条目正文（保留块外用户手写内容） */
export function embedChronicleBlock(fullContent: string, rounds: Map<number, string>): string {
  const { before, after } = extractChronicleInner(fullContent);
  const inner = serializeChronicleRounds(rounds);
  const block = `${MARK_START}\n${inner}\n${MARK_END}`;
  const hadBlock = fullContent.includes(MARK_START) && fullContent.includes(MARK_END);
  if (!hadBlock && before.trim() === fullContent.trim()) {
    return `${fullContent.trimEnd()}\n\n${block}\n`;
  }
  return `${before}${block}${after}`;
}

export async function resolveCharBoundWorldbookWithEntry(): Promise<string | null> {
  const { primary, additional } = getCharWorldbookNames('current');
  const names = [primary, ...(additional ?? [])].filter((n): n is string => Boolean(n));
  for (const wb of names) {
    try {
      const book = await getWorldbook(wb);
      if (book.some(e => e.name === CHRONICLE_ENTRY_NAME)) {
        return wb;
      }
    } catch {
      continue;
    }
  }
  return null;
}

/**
 * @returns 是否对世界书做了修改（无修改则不 replace）
 */
export function applyChronicleUpdate(
  content: string,
  n: number,
  newSum: string,
): { content: string; changed: boolean } {
  const rounds = parseChronicleRounds(content);
  const keys = [...rounds.keys()];
  const maxKey = keys.length ? Math.max(...keys) : undefined;

  const isRollback = rounds.has(n) && maxKey !== undefined && maxKey > n;

  if (isRollback) {
    rounds.set(n, newSum);
    for (const k of [...rounds.keys()]) {
      if (k > n) {
        rounds.delete(k);
      }
    }
    return { content: embedChronicleBlock(content, rounds), changed: true };
  }

  const prev = rounds.get(n);
  if (prev === newSum) {
    return { content, changed: false };
  }
  rounds.set(n, newSum);
  return { content: embedChronicleBlock(content, rounds), changed: true };
}
