/**
 * 监听新增 assistant 楼层，把 &lt;sum&gt; 同步到当前角色绑定世界书中的条目「玩家的游戏历史」。
 * 条目内需预留或由脚本首次写入 &lt;编年史数据&gt;…&lt;/编年史数据&gt; 块（见 chronicleWorldbook.ts）。
 */
import {
  applyChronicleUpdate,
  CHRONICLE_ENTRY_NAME,
  resolveCharBoundWorldbookWithEntry,
} from './chronicleWorldbook';
import { chronicleIndexFromAssistantMessageId, parseAssistantSum } from './assistantSum';

let queue: Promise<void> = Promise.resolve();

function enqueue(task: () => Promise<void>): void {
  queue = queue.then(task).catch(e => {
    console.error('[编年史同步]', e);
    toastr.error(e instanceof Error ? e.message : String(e), '编年史同步失败');
  });
}

async function syncChronicleForAssistant(messageId: number, raw: string): Promise<void> {
  const sum = parseAssistantSum(raw);
  if (!sum) {
    console.info(`[编年史同步] 第 ${messageId} 楼 assistant 未解析到 <sum>，跳过`);
    return;
  }

  const n = chronicleIndexFromAssistantMessageId(messageId);
  const wbName = await resolveCharBoundWorldbookWithEntry();
  if (!wbName) {
    console.warn(`[编年史同步] 角色绑定世界书中未找到条目「${CHRONICLE_ENTRY_NAME}」，跳过`);
    return;
  }

  await updateWorldbookWith(wbName, book => {
    const i = book.findIndex(e => e.name === CHRONICLE_ENTRY_NAME);
    if (i === -1) {
      return book;
    }
    const entry = book[i];
    const { content, changed } = applyChronicleUpdate(entry.content ?? '', n, sum);
    if (!changed) {
      return book;
    }
    const next = [...book];
    next[i] = { ...entry, content };
    return next;
  });
}

$(() => {
  console.info('[编年史同步] 已监听 MESSAGE_RECEIVED → 同步「玩家的游戏历史」');

  eventOn(tavern_events.MESSAGE_RECEIVED, (messageId: number) => {
    const list = getChatMessages(messageId);
    const m = list[0];
    if (!m || m.role !== 'assistant') {
      return;
    }
    enqueue(async () => {
      await syncChronicleForAssistant(m.message_id, m.message ?? '');
    });
  });
});
